1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface Item {
6	  type: string;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	}
11	
12	const PROCESSING_FEE = 5;
13	// Base premiums for main (non-component) items. Components such as runes are
14	// priced separately via componentBasePremium and never read from this table.
15	const BASE_PREMIUMS: Record<string, number> = {
16	  sword: 100,
17	  amulet: 60,
18	  staff: 80,
19	  potion: 40,
20	};
21	const FIRST_INSURANCE_RATE = 0.1;
22	const CURSE_SURCHARGE_RATE = 0.5;
23	const HIGH_ENCHANTMENT_RATE = 0.3;
24	const HIGH_ENCHANTMENT_THRESHOLD = 5;
25	const LOYALTY_THRESHOLD_YEARS = 2;
26	const LOYALTY_DISCOUNT_RATE = 0.2;
27	const FOLLOWUP_DISCOUNT_RATE = 0.15;
28	
29	const sum = (values: number[]): number =>
30	  values.reduce((total, value) => total + value, 0);
31	
32	// Item-specific surcharges, each a rate applied additively to the base premium
33	// when its condition holds. First insurance always applies; the rest are
34	// conditional on the item.
35	const mainItemSurchargeRates = (item: Item): number[] => [
36	  FIRST_INSURANCE_RATE,
37	  ...(item.cursed ? [CURSE_SURCHARGE_RATE] : []),
38	  ...((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
39	    ? [HIGH_ENCHANTMENT_RATE]
40	    : []),
41	];
42	
43	// The additive surcharge model: a base premium scaled by 1 plus the sum of all
44	// applicable rates. Shared by every premium path (single source of truth).
45	const applyRates = (basePremium: number, rates: number[]): number =>
46	  basePremium * (1 + sum(rates));
47	
48	// A main item's premium: its base premium with all applicable surcharge rates applied.
49	const mainItemPremium = (item: Item): number =>
50	  applyRates(BASE_PREMIUMS[item.type], mainItemSurchargeRates(item));
51	
52	const COMPONENT_TYPES = ["rune", "moonstone"];
53	const COMPONENT_BASE_PREMIUM = 25;
54	const COMPONENT_BLOCK_SIZE = 3;
55	const COMPONENT_BLOCK_PREMIUM = 60;
56	
57	const isComponent = (item: Item): boolean =>
58	  COMPONENT_TYPES.includes(item.type);
59	
60	// Base premium for `count` alike components: a block premium applies only for
61	// exactly one block's worth (3) of components; otherwise each is priced individually.
62	const componentBasePremium = (count: number): number => {
63	  if (count === COMPONENT_BLOCK_SIZE) return COMPONENT_BLOCK_PREMIUM;
64	  return count * COMPONENT_BASE_PREMIUM;
65	};
66	
67	const countByType = (items: Item[]): Map<string, number> => {
68	  const counts = new Map<string, number>();
69	  for (const item of items) {
70	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
71	  }
72	  return counts;
73	};
74	
75	// The block rule is per-type ("alike" = same type), so price each type's count
76	// independently. componentBasePremium(count) is the raw per-type base; both the
77	// surcharged premium and the policy-wide raw base build on it.
78	const componentTypeBases = (componentItems: Item[]): number[] =>
79	  [...countByType(componentItems).values()].map(componentBasePremium);
80	
81	const componentItemsBase = (componentItems: Item[]): number =>
82	  sum(componentTypeBases(componentItems).map(withFirstInsurance));
83	
84	// Every item is treated as first insurance today, so the surcharge is applied
85	// uniformly to each base premium, using the same additive rate as main items.
86	const withFirstInsurance = (basePremium: number): number =>
87	  applyRates(basePremium, [FIRST_INSURANCE_RATE]);
88	
89	// Round up in MHPCO's favour, guarding against floating-point noise
90	// (e.g. 197.50000000001 should still round to 198, not 199).
91	const roundUpInMHPCOFavor = (amount: number): number =>
92	  Math.ceil(Number(amount.toFixed(6)));
93	
94	export const quote = (
95	  items: Item[],
96	  customer: Customer,
97	  contractIndex: number,
98	): number => {
99	  const mainItems = items.filter((item) => !isComponent(item));
100	  const componentItems = items.filter((item) => isComponent(item));
101	
102	  const mainBase = sum(mainItems.map(mainItemPremium));
103	  const componentBase = componentItemsBase(componentItems);
104	
105	  // The policy base premium is the sum of raw item base premiums (no item
106	  // surcharges); policy-wide discounts are percentages of this amount.
107	  const rawMainBase = sum(mainItems.map((item) => BASE_PREMIUMS[item.type]));
108	  const rawComponentBase = sum(componentTypeBases(componentItems));
109	  const policyBasePremium = rawMainBase + rawComponentBase;
110	
111	  const loyaltyDiscount =
112	    customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS
113	      ? LOYALTY_DISCOUNT_RATE * policyBasePremium
114	      : 0;
115	  const followUpDiscount =
116	    contractIndex >= 1 ? FOLLOWUP_DISCOUNT_RATE * policyBasePremium : 0;
117	
118	  return roundUpInMHPCOFavor(
119	    mainBase + componentBase - loyaltyDiscount - followUpDiscount + PROCESSING_FEE,
120	  );
121	};
122	
123	export const claim = (): number => {
124	  return undefined as unknown as number;
125	};
